import org.springframework.security.crypto.bcrypt.BCryptPasswordEncoder;   //Import BCrypt Password Encryption library for Spring Security which provides password hashing methods like bcrypt, scrypt etc.. It's a part of the spring security core and can be used standalone too without any additional dependencies
import org.springframework.stereotype.Controller; 	//Spring stereotypes that marks classes as candidate targets where bean instantiation could occur (used for dependency injection)
  
@Controller //This class java_45698_CredentialValidator_A03 interact with Spring's IoC container, which is a mechanism to manage objects through the life of an application in one way or another and provides features like injected dependencies. 
public class CredentialValidator {   		//Our main program logic/method that contains our custom validation methods (to be filled by actual users)   //Class name should match what's used for Dependency Injection later on when we create instances of this classes via Spring context and Bean Factory. 
     private BCryptPasswordEncoder passwordEncoder;   		//This class will use Bcrypt to hash the user-provided plaintext credentials into secure, hashed (and salted) versions for storage in our database which is a security feature not offered by default through Spring Security   //Dependency Injection of spring's core library
     public CredentialValidator(BCryptPasswordEncoder passwordEncoder){ 	//Constructor that will allow us to inject BCrypt Password Encoding into this bean (this means we are using the Dependency injection feature)	This is done by Spring during context creation, so it’ll be available in our method parameters.
         this.passwordEncoder = passwordEncoder;   //Setting up dependency for BcryptPasswordEncoding from above line and then initializing object of class with provided BCrypt encoding library (which will use the bcrypt algorithm)		//Spring's @Autowired annotation is used to achieve Dependency Injection in Java.
     } 		   					   //The constructor has one parameter: an instance of our own CustomUserDetailsService, which we need for UserDetail Service and also this will be called during Spring’ context setup by the application		//This helps us with dependency injection between classes using setter methods (setters are used in Java to provide dependencies). 
     //...Implement your custom validation logic here..//The rest of method should not cause any security issue as it's only about credential-related operations. For real world applications, you will need more advanced mechanisms like OAuth2 or JWT tokens for authentication and authorization (also by Spring Security).
}